<script setup>
import { onMounted, onUnmounted, computed } from 'vue';
import Splide from '@splidejs/splide';
import { AutoScroll } from '@splidejs/splide-extension-auto-scroll';
import '@splidejs/splide/css';
import DashboardDocumentCard from '@/components/DashboardDocumentCard.vue';

// Get user id from localStorage
const getUserId = () => {
  try {
    const userRaw = localStorage.getItem('user');
    const user = userRaw ? JSON.parse(userRaw) : null;
    return user?.id ? String(user.id) : '';
  } catch {
    return '';
  }
};

// Computed route based on user id
const dashboardRoute = computed(() => {
  const userId = getUserId();
  return userId === '2901' ? '/pdf/flow-dash2' : '/pdf/flow-dash';
});

let splideInstances = [];
onMounted(() => {
  const splideElements = document.querySelectorAll('.splide');  
  splideElements.forEach((el) => {
    const options = el.dataset.splide ? JSON.parse(el.dataset.splide) : {};    
    const fraction = el.querySelector('.splide__fraction');    
    const splide = new Splide(el, options);    
    if (fraction) {
      splide.on('mounted move', () => {
        const total = splide.length;
        const current = splide.index + 1;
        fraction.textContent = `${current}/${total}`;
      });
    }    
    if (options.autoScroll) {
      splide.mount({ AutoScroll });
    } else {
      splide.mount();
    }    
    splideInstances.push(splide);
  });
});

onUnmounted(() => {
  splideInstances.forEach((splide) => {
    if (splide) {
      splide.destroy();
    }
  });
  splideInstances = [];
});
</script>